{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires applying the hydrogenic model to an exciton system. The first step must define the relationship between the binding energy and the Rydberg constant, specifically addressing the sign convention for energy levels relative to the band edge. The second step involves calculating the specific energy level for n=3.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Define the physical relationship between the exciton binding energy (Eb) and the effective Rydberg energy (Ry*). Establish the sign convention where the energy of the 1s state is defined relative to the band gap (Eg), such that E(1s) = Eg - Eb. Define the formula for the energy of the nth state in a hydrogenic model as E(n) = Eg - Ry*/n^2, where Ry* is the binding energy of the 1s state."
    },
    {
      "label": "helper_2",
      "instructions": "Using the established definitions, calculate the value of the effective Rydberg energy (Ry*) from the given 1s exciton peak energy (1 eV) and the band gap (3 eV). Then, use the formula E(n) = Eg - Ry*/n^2 to calculate the energy level for n = 3. Provide the final numerical result for the energy level of the n=3 state."
    }
  ],
  "synthesis_brief": "Combine the definition of the effective Rydberg energy and the n-dependent energy formula from helper 1 with the numerical calculation of Ry* and the resulting E(3) from helper 2 to provide the final energy value."
}

